package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        // Create a CSVFormat instance using the default constructor via reflection
        // because the constructor is private, so we use one of the predefined constants
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsQuoteCharacterSet_WhenQuoteCharacterIsSet() throws Exception {
        // Use reflection to set the private final field quoteCharacter to a non-null value
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, '\"');

        assertTrue(csvFormat.isQuoteCharacterSet());
    }

    @Test
    void testIsQuoteCharacterSet_WhenQuoteCharacterIsNull() throws Exception {
        // Use reflection to set the private final field quoteCharacter to null
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, null);

        assertFalse(csvFormat.isQuoteCharacterSet());
    }
}
